
public class JogoDeXadrez implements Jogo{    @Override    public void iniciar()    {        Tabuleiro tabuleiro = new Tabuleiro();        Jogador jogadorHumano =                new JogadorHumano('b');        Jogador jogadorSintetico =                new JogadorSintetico('p');        boolean continuar = true;        while (!tabuleiro.acabouOJogo() && continuar)        {            continuar = jogadorHumano.jogar(                    tabuleiro,                    "",                    0            );            if (continuar)            {                jogadorSintetico.jogar(                        tabuleiro,                        "P1p",                        1                );            }        }    }    public static void main(String[] args)    {        JogoDeXadrez jogo = new JogoDeXadrez();        jogo.iniciar();        System.out.println("SEU NOME AQUI");    }}
